import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Chapter 4: Anatomy of an Agentic Loop","description":"The core runtime pattern of every coding agent — from input processing through LLM invocation, tool dispatch, and observation collection.","frontmatter":{"title":"Chapter 4: Anatomy of an Agentic Loop","description":"The core runtime pattern of every coding agent — from input processing through LLM invocation, tool dispatch, and observation collection."},"headers":[],"relativePath":"learn/linear/04-anatomy-of-an-agentic-loop/index.md","filePath":"learn/linear/04-anatomy-of-an-agentic-loop/index.md"}'),i={name:"learn/linear/04-anatomy-of-an-agentic-loop/index.md"};function l(r,e,s,c,h,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="anatomy-of-an-agentic-loop" tabindex="-1">Anatomy of an Agentic Loop <a class="header-anchor" href="#anatomy-of-an-agentic-loop" aria-label="Permalink to &quot;Anatomy of an Agentic Loop&quot;">​</a></h1><p>The agentic loop is the beating heart of every coding agent. It is the runtime pattern that transforms a stateless language model into an autonomous system capable of multi-step reasoning and action. Understanding this loop in detail is the single most important concept in this entire tutorial track, because every feature you build later — tools, file operations, shell commands — plugs into this central loop.</p><p>This chapter dissects the agentic loop into its constituent phases: input processing, LLM invocation, tool call detection, tool dispatch, observation collection, and response generation. We model the loop as a state machine with well-defined transitions, making it possible to reason about error states, stop conditions, and recovery strategies. You will see how the abstract pattern maps to concrete implementations in production agents.</p><p>By the end of this chapter, you will have a complete mental model of the agentic loop and be ready to implement one in Rust. You will understand not just the happy path, but also the edge cases: what happens when a tool fails, when the model hallucinates a tool that does not exist, or when the conversation exceeds the context window mid-loop.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Model the agentic loop as a state machine with explicit states and transitions</li><li>Identify the six phases of a single loop iteration and their responsibilities</li><li>Understand how tool call detection bridges the LLM response and tool execution</li><li>Design stop conditions that prevent infinite loops while allowing complex multi-step tasks</li><li>Handle error states gracefully including tool failures, API errors, and context overflow</li><li>Compare loop variants across production agents and understand their design trade-offs</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/04-anatomy-of-an-agentic-loop/01-the-repl-pattern.html">The REPL Pattern</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/02-from-chatbot-to-agent.html">From Chatbot to Agent</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/03-state-machine-model.html">State Machine Model</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/04-input-processing.html">Input Processing</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/05-llm-invocation.html">LLM Invocation</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/06-tool-call-detection.html">Tool Call Detection</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/07-tool-dispatch.html">Tool Dispatch</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/08-observation-collection.html">Observation Collection</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/09-response-generation.html">Response Generation</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/10-stop-conditions.html">Stop Conditions</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/11-error-states.html">Error States</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/12-loop-variants.html">Loop Variants</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/13-real-world-implementations.html">Real World Implementations</a></li><li><a href="/linear/04-anatomy-of-an-agentic-loop/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 3 (understanding of LLM APIs and tool use)</li></ul>',10)])])}const f=a(i,[["render",l]]);export{m as __pageData,f as default};
